code.C:
#include <stdio.h>
#define MOD 1000000007

long long countGoodNumbers(int n) {
    long long res = 1;
    for (int i = 0; i < n; i++) {
        if (i % 2 == 0) res = (res * 5) % MOD;
        else res = (res * 4) % MOD;
    }
    return res;
}

int main() {
    int n = 1;
    printf("%lld\n", countGoodNumbers(n));
    return 0;
}

