code.Java:
public class Solution {
    static final int MOD = 1000000007;
    public static int countGoodNumbers(int n) {
        long res = 1;
        for (int i = 0; i < n; i++) {
            if (i % 2 == 0) res = (res * 5) % MOD;
            else res = (res * 4) % MOD;
        }
        return (int)res;
    }
    public static void main(String[] args) {
        int n = 1;
        System.out.println(countGoodNumbers(n));
    }
}

